import software.amazon.awssdk.auth.credentials.{AwsCredentialsProvider, DefaultCredentialsProvider, ProfileCredentialsProvider}
import software.amazon.awssdk.regions.Region
import software.amazon.awssdk.services.s3.S3Client
import software.amazon.awssdk.services.s3.model.{ListBucketsResponse, S3Exception}
import scala.jdk.CollectionConverters._

class AwsService(awsRegion: Region, profileName: Option[String] = None) {

  private val credentialsProvider: AwsCredentialsProvider = profileName match {
    case Some(profile) =>
      println(s"Using AWS profile: $profile")
      ProfileCredentialsProvider.builder().profileName(profile).build()
    case None =>
      println("Using default AWS credential chain (environment variables, shared config, EC2 instance profile, etc.)")
      DefaultCredentialsProvider.create()
  }

  // Lazily initialized S3 client to ensure credentialsProvider is ready
  private lazy val s3Client: S3Client = S3Client.builder()
    .region(awsRegion)
    .credentialsProvider(credentialsProvider)
    .build()

  /**
   * Lists all S3 buckets available to the configured AWS credentials.
   *
   * @return A list of bucket names.
   */
  def listS3Buckets(): List[String] = {
    try {
      println(s"Attempting to list S3 buckets in region ${awsRegion.id()}...")
      val response: ListBucketsResponse = s3Client.listBuckets()
      val buckets = response.buckets().asScala.map(_.name()).toList
      println(s"Successfully listed ${buckets.size} buckets.")
      buckets
    } catch {
      case e: S3Exception =>
        System.err.println(s"S3Exception during listBuckets: ${e.awsErrorDetails().errorMessage()}")
        System.err.println(s"Error code: ${e.awsErrorDetails().errorCode()}")
        throw e
      case e: Exception =>
        System.err.println(s"An unexpected error occurred: ${e.getMessage}")
        throw e
    }
  }

  /**
   * Closes the S3 client when the service is no longer needed.
   */
  def close(): Unit = {
    println("Closing S3 client.")
    s3Client.close() // This will only be called if s3Client was initialized
  }
}

